// src/components/Navbar.jsx
import React from 'react';
import GlobeLogo from './GlobeLogo';
//import LanguageSelector from './LanguageSelector';

const NAV_ITEMS = [
  { page: 'home',     label: 'Home'        },
  { page: 'location', label: 'Location'    },
  { page: 'dest',     label: 'Destination' },
  { page: 'trains',   label: 'Trains'      },
  { page: 'lastmile', label: 'Last Mile'   },
];

export default function Navbar({ currentPage, onNavigate, speak }) {
  return (
    <nav style={{
      position: 'fixed', top: 0, left: 0, right: 0, zIndex: 5000,
      display: 'flex', alignItems: 'center', justifyContent: 'space-between',
      padding: '10px 28px',
      background: 'rgba(255,255,255,0.97)',
      backdropFilter: 'blur(22px)',
      borderBottom: '1px solid rgba(0,0,0,.07)',
      boxShadow: '0 1px 12px rgba(0,0,0,.06)',
      animation: 'slideDown .8s ease forwards',
    }}>

      {/* Brand */}
      <div
        onClick={() => onNavigate('home')}
        style={{ display: 'flex', alignItems: 'center', gap: 10, cursor: 'pointer', userSelect: 'none' }}
      >
        <div style={{
          background: '#1e1e1c', borderRadius: '50%', padding: 3,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
        }}>
          <GlobeLogo size={36} />
        </div>
        <div style={{
          fontFamily: 'Playfair Display, serif', fontWeight: 900,
          fontSize: '1.35rem', color: '#1a1a19', letterSpacing: 5, lineHeight: 1,
        }}>VISTA</div>
      </div>

      {/* Nav + controls */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
        {NAV_ITEMS.map(item => (
          <button
            key={item.page}
            onClick={() => onNavigate(item.page)}
            style={{
              background: currentPage === item.page ? '#6BAF45' : 'transparent',
              color: currentPage === item.page ? '#fff' : '#6a6a64',
              border: 'none', cursor: 'pointer', padding: '8px 14px', borderRadius: 8,
              fontSize: '.82rem', fontWeight: currentPage === item.page ? 600 : 500,
              fontFamily: 'Inter, sans-serif', transition: 'all .25s',
            }}
            onMouseEnter={e => { if (currentPage !== item.page) { e.target.style.color = '#1a1a19'; e.target.style.background = 'rgba(0,0,0,.05)'; }}}
            onMouseLeave={e => { if (currentPage !== item.page) { e.target.style.color = '#6a6a64'; e.target.style.background = 'transparent'; }}}
          >{item.label}</button>
        ))}

        //{/* Language selector */}
        <div style={{ marginLeft: 4 }}>
          <LanguageSelector speak={speak} compact={true} />
        </div>

        {/* Start Journey CTA */}
        <button
          onClick={() => onNavigate('location')}
          style={{
            marginLeft: 8, padding: '9px 20px', borderRadius: 50,
            background: '#1e1e1c', color: '#ffffff', border: 'none', cursor: 'pointer',
            fontFamily: 'Inter, sans-serif', fontSize: '.83rem', fontWeight: 600,
            letterSpacing: '.3px', boxShadow: '0 2px 10px rgba(0,0,0,.15)', transition: 'all .25s',
          }}
          onMouseEnter={e => { e.currentTarget.style.background = '#333'; e.currentTarget.style.transform = 'scale(1.02)'; }}
          onMouseLeave={e => { e.currentTarget.style.background = '#1e1e1c'; e.currentTarget.style.transform = 'scale(1)'; }}
        >Start Journey</button>
      </div>
    </nav>
  );
}
